\end{definition}

\begin{definition}

\leanok
[Chart morphism to $\spec\mathcal A_0$]
  \label{def:projchart-to-speczero}
  \lean{MR2223407ConstructionHilbertQuot.projChartToSpecZero}
  \uses{def:projchart}
